fun solve(nums: Array<Long>): Long {
    fun isPrime(n: Int): Boolean {
        if (n <= 1) return false
        if (n == 2) return true
        if (n % 2 == 0) return false
        var i = 3
        while (i * i <= n) {
            if (n % i == 0) return false
            i += 2
        }
        return true
    }

    var sumA = 0L
    var sumB = 0L

    for (i in nums.indices) {
        if (isPrime(i)) {
            sumA += nums[i]
        } else {
            sumB += nums[i]
        }
    }

    return Math.abs(sumA - sumB)
}
